import{_ as d,o as e,c as a,ag as o}from"./chunks/framework.HG0H2VLS.js";const g=JSON.parse('{"title":"Accordion — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/Accordion/Accordion.figma-notes.md","filePath":"public/demos/src/components/Accordion/Accordion.figma-notes.md"}'),r={name:"public/demos/src/components/Accordion/Accordion.figma-notes.md"};function c(i,t,n,s,l,p){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="accordion-—-figma-notes" tabindex="-1">Accordion — Figma Notes <a class="header-anchor" href="#accordion-—-figma-notes" aria-label="Permalink to &quot;Accordion — Figma Notes&quot;">​</a></h1><p><strong>Figma URL:</strong> <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2527-2622" target="_blank" rel="noreferrer">node 2527:2622</a></p><h2 id="component-set" tabindex="-1">Component Set <a class="header-anchor" href="#component-set" aria-label="Permalink to &quot;Component Set&quot;">​</a></h2><p>Accordion is a Tier=Component design-system component. Each item has a header (trigger) that toggles a body panel below. Variants control the container styling and size.</p><h2 id="variant-×-size-matrix" tabindex="-1">Variant × Size Matrix <a class="header-anchor" href="#variant-×-size-matrix" aria-label="Permalink to &quot;Variant × Size Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Node</th><th>Type</th><th>Size</th><th>Notes</th></tr></thead><tbody><tr><td><code>2527:2621</code></td><td>Default</td><td>Default</td><td>Bordered container, single-open behaviour</td></tr><tr><td><code>2527:2742</code></td><td>Default</td><td>sm</td><td>Smaller header (40px) and tighter typography</td></tr><tr><td><code>2527:2619</code></td><td>Separated Cards</td><td>Default</td><td>Each item is its own card with shadow + gap between cards</td></tr><tr><td><code>2527:2764</code></td><td>Separated Cards</td><td>sm</td><td>Smaller separated cards</td></tr><tr><td><code>2527:2618</code></td><td>All Open</td><td>Default</td><td>Multiple items can be open at once (JS only — same CSS)</td></tr><tr><td><code>2527:2786</code></td><td>All Open</td><td>sm</td><td>Smaller all-open</td></tr><tr><td><code>2527:2617</code></td><td>Flush</td><td>Default</td><td>Top + bottom border only — no card chrome, transparent triggers</td></tr><tr><td><code>2527:2811</code></td><td>Flush</td><td>sm</td><td>Smaller flush</td></tr><tr><td><code>2527:2620</code></td><td>Nested</td><td>Default</td><td>Default container with another <code>.acc</code> inside an open panel</td></tr><tr><td><code>2527:2829</code></td><td>Nested</td><td>sm</td><td>Smaller nested</td></tr></tbody></table><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma property</th><th>CSS class</th></tr></thead><tbody><tr><td>Type=Default</td><td><code>.acc</code> (base)</td></tr><tr><td>Type=Separated Cards</td><td><code>.acc--separated</code></td></tr><tr><td>Type=All Open</td><td><code>.acc</code> with <code>data-acc=&quot;multi&quot;</code> (JS)</td></tr><tr><td>Type=Flush</td><td><code>.acc--flush</code></td></tr><tr><td>Type=Nested</td><td><code>.acc__panel &gt; .acc</code> (composition only)</td></tr><tr><td>Size=Default</td><td><code>.acc</code> (base)</td></tr><tr><td>Size=sm</td><td><code>.acc--sm</code></td></tr><tr><td>Item open</td><td><code>.acc__item--open</code> (JS adds on click)</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Value</th></tr></thead><tbody><tr><td>Container bg</td><td><code>--ai-surface-primary</code></td><td>#ffffff</td></tr><tr><td>Container border</td><td><code>--ai-border-secondary</code></td><td>#e2e2e3</td></tr><tr><td>Container radius</td><td><code>--ai-radius-md</code></td><td>8px</td></tr><tr><td>Container inner padding</td><td><code>1px</code></td><td>spacing/px (raw — optical inner offset)</td></tr><tr><td>Trigger bg</td><td><code>--ai-surface-minimal</code></td><td>#f6f6f7</td></tr><tr><td>Trigger hover bg</td><td><code>--ai-surface-secondary</code></td><td>#e2e2e3</td></tr><tr><td>Trigger height (Default)</td><td><code>--ai-spacing-10</code></td><td>56px</td></tr><tr><td>Trigger height (sm)</td><td><code>--ai-spacing-8</code></td><td>40px</td></tr><tr><td>Trigger padding (Default)</td><td><code>--ai-spacing-5</code> v / <code>--ai-spacing-6</code> h</td><td>16/24px</td></tr><tr><td>Trigger padding (sm)</td><td><code>--ai-spacing-5</code></td><td>16px</td></tr><tr><td>Trigger font</td><td><code>--ai-font-title</code> <code>--ai-font-semibold</code></td><td>Inter 600</td></tr><tr><td>Trigger size (Default)</td><td><code>--ai-font-fixed-sm</code></td><td>16px</td></tr><tr><td>Trigger size (sm)</td><td><code>--ai-font-fixed-xs</code></td><td>14px</td></tr><tr><td>Trigger color</td><td><code>--ai-text-primary</code></td><td>#212123</td></tr><tr><td>Item separator</td><td><code>--ai-border-secondary</code></td><td>1px</td></tr><tr><td>Panel bg</td><td><code>--ai-surface-primary</code></td><td>#ffffff (inherits container)</td></tr><tr><td>Panel border-top</td><td><code>--ai-border-secondary</code></td><td>1px</td></tr><tr><td>Panel padding (Default)</td><td><code>--ai-spacing-5</code> t / <code>--ai-spacing-6</code> h+b</td><td>16/24/24px</td></tr><tr><td>Panel padding (sm)</td><td><code>--ai-spacing-5</code></td><td>16px all</td></tr><tr><td>Panel text</td><td><code>--ai-text-secondary</code></td><td>#3c3c3f</td></tr><tr><td>Panel size (Default)</td><td><code>--ai-font-fixed-xs</code></td><td>14px</td></tr><tr><td>Panel size (sm)</td><td><code>--ai-font-fixed-xxs</code></td><td>12px</td></tr><tr><td>Panel line-height (Default)</td><td><code>--ai-leading-md</code></td><td>24px</td></tr><tr><td>Panel line-height (sm)</td><td><code>--ai-leading-sm</code></td><td>20px</td></tr><tr><td>Chevron icon size</td><td><code>--ai-icon-size-sm</code></td><td>16px</td></tr><tr><td>Chevron color</td><td><code>--ai-icon-contrast</code></td><td>#929295</td></tr><tr><td>Separated card gap</td><td><code>--ai-spacing-3</code></td><td>8px</td></tr><tr><td>Separated card shadow</td><td><code>0 1px 3px rgba(0,0,0,0.05)</code></td><td>static (raw — card elevation)</td></tr><tr><td>Nested gap from paragraph</td><td><code>--ai-spacing-4</code></td><td>12px (<code>margin-top</code> on <code>.acc__panel .acc</code>)</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None — all colour, spacing, typography, and radius values resolve to existing <code>--ai-*</code> tokens. The <code>1px</code> inner padding and the raw separated-card box-shadow are optical/structural values per CLAUDE rules and don&#39;t require tokens.</p><h2 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to &quot;Icons&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Lucide name</th></tr></thead><tbody><tr><td>Header chevron</td><td><code>chevron-down</code></td></tr></tbody></table><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><p>None — Accordion is a self-contained atomic component. It composes Lucide icons via the project&#39;s standard <code>&lt;i data-lucide&gt;</code> pattern.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Single-open vs multi-open behaviour is controlled by <code>data-acc=&quot;single&quot;</code> (default) or <code>data-acc=&quot;multi&quot;</code> (All Open).</li><li>Headings use <code>&lt;h3&gt;</code> for top-level accordions and <code>&lt;h4&gt;</code> for nested accordions to maintain semantic hierarchy. The <code>.acc__heading</code> class strips default heading margins/typography so the <code>&lt;button&gt;</code> controls the appearance.</li><li>Chevron rotates 180deg via <code>.acc__item--open .acc__chevron { transform: rotate(180deg) }</code>.</li><li>Type=Nested doesn&#39;t add any new CSS — it&#39;s the same as Default with another <code>.acc</code> placed inside an <code>.acc__panel</code>. The panel adds <code>margin-top</code> to the nested accordion for breathing room from the paragraph above it.</li><li>Type=Separated Cards uses <code>gap</code> between items and gives each item its own border, radius, and subtle shadow. Closed items show as fully grey (the trigger&#39;s bg-minimal fills the card); open items show grey trigger + white body.</li><li>Type=Flush removes the outer card and shows only top + bottom borders on the container, with transparent triggers and no horizontal padding so the header text aligns to the parent surface.</li><li>Trigger hover is suppressed on Flush variant (transparent bg with hover would jar visually against the parent surface).</li><li>Each item announces its expanded state via <code>aria-expanded</code> set by JS on click.</li></ul>',18)])])}const m=d(r,[["render",c]]);export{g as __pageData,m as default};
